import json
import sys
from http.server import HTTPServer, BaseHTTPRequestHandler

N = 5
start = (1,1)
exit_pos = (N, N)
current = list(start)
visits = {}

def visit_count(pos):
    return visits.get(tuple(pos), 0)

def inc_visit(pos):
    key = tuple(pos)
    visits[key] = visits.get(key, 0) + 1
    if visits[key] > 2:
        return False
    return True

def connectivity(pos):
    # all directions open within bounds
    up = 1 if pos[1] < N else 0
    down = 1 if pos[1] > 1 else 0
    left = 1 if pos[0] > 1 else 0
    right = 1 if pos[0] < N else 0
    return [up, down, left, right]

class MazeHandler(BaseHTTPRequestHandler):
    def do_GET(self):
        if self.path == '/maze_size':
            self.send_response(200)
            self.send_header('Content-Type', 'application/json')
            self.end_headers()
            self.wfile.write(json.dumps({'maze_size': N}).encode())
        elif self.path == '/sense':
            self.send_response(200)
            self.send_header('Content-Type', 'application/json')
            self.end_headers()
            self.wfile.write(json.dumps({'connectivity': connectivity(current)}).encode())
        else:
            self.send_response(404)
            self.end_headers()

    def do_POST(self):
        content_length = int(self.headers.get('Content-Length', 0))
        body = self.rfile.read(content_length).decode('utf-8')
        data = json.loads(body) if body else {}

        if self.path == '/move':
            direction = data.get('direction')
            # 0 up,1 down,2 left,3 right
            new = current[:]
            if direction == 0:
                new[1] += 1
            elif direction == 1:
                new[1] -= 1
            elif direction == 2:
                new[0] -= 1
            elif direction == 3:
                new[0] += 1
            # check bounds and connectivity
            conn = connectivity(current)
            if conn[direction] == 1:
                if not inc_visit(new):
                    # game over
                    self.send_response(200)
                    self.send_header('Content-Type', 'application/json')
                    self.end_headers()
                    self.wfile.write(json.dumps({'connectivity': [0,0,0,0]}).encode())
                    return
                current[0], current[1] = new[0], new[1]
                self.send_response(200)
                self.send_header('Content-Type', 'application/json')
                self.end_headers()
                self.wfile.write(json.dumps({'status': 'moved'}).encode())
            else:
                self.send_response(400)
                self.end_headers()
        elif self.path == '/finish':
            if current[0] == exit_pos[0] and current[1] == exit_pos[1]:
                self.send_response(200)
                self.send_header('Content-Type', 'application/json')
                self.end_headers()
                self.wfile.write(json.dumps({'status': 'Congratulations, destination reached'}).encode())
            else:
                self.send_response(200)
                self.send_header('Content-Type', 'application/json')
                self.end_headers()
                self.wfile.write(json.dumps({'status': 'illegal', 'message': 'Not at destination, game over'}).encode())
        else:
            self.send_response(404)
            self.end_headers()

    def log_message(self, format, *args):
        pass

if __name__ == '__main__':
    server = HTTPServer(('0.0.0.0', 8088), MazeHandler)
    print('Starting maze server on port 8088...')
    server.serve_forever()
EOF
